import React from 'react';
import { useWebSocket } from '../hooks/useWebSocket';

const DashboardOverview = () => {
    const { data, isConnected } = useWebSocket("ws://localhost:8000/ws");

    if (!data) return <div className="p-8 text-white">Loading Enterprise Telemetry...</div>;

    return (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
            <div className="bg-gray-800 rounded-xl p-6 border border-gray-700 shadow-lg">
                <h3 className="text-gray-400 text-sm font-medium uppercase tracking-wider mb-2">Active Agents</h3>
                <div className="flex items-end gap-3">
                    <span className="text-4xl font-bold text-white">{data.current_metrics.active_agents}</span>
                    <span className="text-emerald-400 text-sm font-medium mb-1 flex items-center">
                        <span className="w-2 h-2 rounded-full bg-emerald-400 mr-2 animate-pulse"></span>
                        Live
                    </span>
                </div>
            </div>

            <div className="bg-gray-800 rounded-xl p-6 border border-gray-700 shadow-lg">
                <h3 className="text-gray-400 text-sm font-medium uppercase tracking-wider mb-2">DB Load (RU/s)</h3>
                <div className="flex items-end gap-3">
                    <span className="text-4xl font-bold text-white">{data.current_metrics.db_load}%</span>
                    <span className="text-yellow-400 text-sm font-medium mb-1">Warning Threshold</span>
                </div>
            </div>

            <div className="bg-gradient-to-br from-emerald-900 to-gray-800 rounded-xl p-6 border border-emerald-800 shadow-lg">
                <h3 className="text-emerald-400 text-sm font-medium uppercase tracking-wider mb-2">Cost Savings (USD)</h3>
                <div className="flex items-end gap-3">
                    <span className="text-4xl font-bold text-white">${data.current_metrics.cost_savings_usd.toLocaleString()}</span>
                    <span className="text-emerald-300 text-sm font-medium mb-1">via Cost Orchestrator</span>
                </div>
            </div>
        </div>
    );
};

export default DashboardOverview;
